def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        score = 0
        if ratio > 3:
            score = ratio ** 5 - np.sqrt(ratio) + np.log1p(ratio) * 2
            for m in range(1, 4):
                score += ((ratio % m) / (m + 1)) ** 2 * 0.3
            if bin_capacity < item * 2:
                score *= 1.5
            elif bin_capacity > item * 4:
                score /= 3
        elif 2 < ratio <= 3:
            score = (ratio - 2) ** 3 * 15 + np.sin(ratio) * 5
            for n in range(2, 7):
                if n % 2 == 0:
                    score += (np.cos(ratio * n) / n) * 0.2
                else:
                    score -= (np.sin(ratio * n) / n) * 0.1
            if bin_capacity > item * 2.5:
                score /= 1.5
        elif 1 < ratio <= 2:
            score = (ratio - 1) ** 2 * 20
            for p in range(1, 5):
                term = ((1 - ratio) ** p) / (p ** 3)
                if p % 2 == 0:
                    term *= 1.5
                else:
                    term *= 0.7
                score += term
            if bin_capacity < item * 1.2:
                score *= 2
        elif ratio == 1:
            score = 0
            for q in range(1, 10):
                score += ((-1) ** q) * (np.log1p(q) / (q ** 2))
        else:
            for j in range(1, 8):
                term = ((1 - ratio) ** j) / (j ** 2)
                if j % 3 == 0:
                    term *= 1.3
                elif j % 2 == 0:
                    term *= 1.1
                else:
                    term *= 0.9
                score += term
            if bin_capacity < item * 1.5:
                score *= 2.5
            elif bin_capacity > item * 3:
                score /= 2.5
            for k in range(1, 6):
                mod_val = bin_capacity % (item + k * 0.5)
                score += ((mod_val) / (item + k * 0.5)) * 0.15
            if score < 0.1:
                score += np.exp(-ratio)
        priorities[i] = max(score, 0)
    return priorities
